INSERT INTO coloring_sections (slug, title, seo_text, created_at)
VALUES
  ('multiki', 'Мультфильмы', 'Мультфильмы — это любимые герои, яркие сюжеты и радость творчества для детей и взрослых. На странице раскрасок «Мультфильмы» собраны картинки с узнаваемыми персонажами, выразительными эмоциями и динамичными сценами.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('kino', 'Кино', 'Раздел раскрасок «Кино» — это возможность создать яркие постеры, героев и фантастические сцены в формате раскраски прямо в браузере. Здесь собраны рисунки, вдохновлённые популярными фильмами и киноисториями.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('games', 'Игры', 'Раскраски «Игры» — место, где знакомые персонажи, уровни и приключения превращаются в красивый рисунок. Здесь вы найдёте подборки раскрасок по игровым темам: герои, персонажи-помощники, фантастические локации.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('skazki', 'Сказки', 'Раздел «Сказки» — это добрые герои, волшебные сцены и захватывающие сюжеты, которые легко и интересно раскрасить в браузере. Здесь собраны раскраски по мотивам сказочных историй.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('priroda', 'Природа', 'Раскраски «Природа» — это красивые пейзажи, деревья, цветы, сезонные сюжеты и всё, что вдохновляет на спокойное творчество. Здесь собраны рисунки с миром вокруг: лес, поля, закаты, растения.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('animals', 'Животные', 'Раздел «Животные» — это раскраски с любимыми питомцами, дикими зверями и персонажами из мультфильмов про животных. Здесь собраны сюжеты, которые легко раскрасить и приятно рассматривать.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('mandaly', 'Мандалы', 'Мандалы — это завораживающие узоры, которые помогают расслабиться и погрузиться в спокойный ритм творчества. В разделе «Мандалы» собраны раскраски с круговыми орнаментами и симметричными деталями.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('cosmos', 'Космос', 'Раскраски «Космос» — это звёзды, планеты, туманности и фантастические пейзажи, которые хочется раскрашивать снова и снова. На странице вы найдёте сюжеты, вдохновлённые вселенной.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('technique', 'Техника', 'Раздел «Техника» — это раскраски про машины, механизмы, детали и изобретения. Здесь собраны рисунки с элементами техники: автомобили, самолёты, роботы, колёса, шестерёнки.', EXTRACT(EPOCH FROM NOW())::BIGINT),
  ('celebrities', 'Знаменитости', 'Раздел «Знаменитости» создан для тех, кто любит узнаваемые образы и вдохновляющие сюжеты. Здесь собраны раскраски с персонажами в стиле известных людей и яркими портретными мотивами.', EXTRACT(EPOCH FROM NOW())::BIGINT)
